import { useState, useEffect } from 'react';
import { useParams, useSearchParams } from 'react-router-dom';
import { FileText, Download, Users, CheckCircle, FileSpreadsheet } from 'lucide-react';
import { PageHeader } from '../../components/common/PageHeader';
import { Card } from '../../components/common/Card';
import { Button } from '../../components/common/Button';
import toast from 'react-hot-toast';
import api from '../../services/api';

const StageWiseReport = () => {
  const { postId } = useParams();
  const [searchParams, setSearchParams] = useSearchParams();
  const [post, setPost] = useState(null);
  const [districts, setDistricts] = useState([]);
  const [selectedDistrict, setSelectedDistrict] = useState(searchParams.get('district_id') || '');
  const [selectedStage, setSelectedStage] = useState(searchParams.get('stage') || 'ELIGIBLE');
  const [stageHistory, setStageHistory] = useState([]);
  const [loading, setLoading] = useState(false);
  const [reportRows, setReportRows] = useState([]);

  const stages = [
    { value: 'ELIGIBLE', label: 'Eligible List', color: 'blue' },
    { value: 'PROVISIONAL_SELECTED', label: 'Provisional Selected', color: 'yellow' },
    { value: 'SELECTED', label: 'Selected List', color: 'green' }
  ];

  useEffect(() => {
    fetchPostDetails();
    fetchDistricts();
  }, [postId]);

  useEffect(() => {
    if (selectedDistrict && selectedStage) {
      fetchStageReport();
    }
  }, [selectedDistrict, selectedStage]);

  const fetchPostDetails = async () => {
    try {
      const response = await api.get(`/posts/${postId}`);
      if (response.data.success) {
        setPost(response.data.data);
      }
    } catch (error) {
      toast.error('Failed to fetch post details');
    }
  };

  const fetchDistricts = async () => {
    try {
      const response = await api.get('/masters/districts');
      if (response.data.success) {
        setDistricts(response.data.data);
      }
    } catch (error) {
      toast.error('Failed to fetch districts');
    }
  };

  const fetchStageReport = async () => {
    setLoading(true);
    try {
      const districtQuery = selectedDistrict
        ? `district_id=${encodeURIComponent(selectedDistrict)}&`
        : '';
      const response = await api.get(
        `/admin/review/posts/${postId}/stage-report?${districtQuery}stage=${selectedStage}`
      );
      if (response.data.success) {
        setStageHistory(response.data.data.stageHistory || []);
        setReportRows(response.data.data.rows || []);
      }
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to fetch stage report');
    } finally {
      setLoading(false);
    }
  };

  const handleDistrictChange = (districtId) => {
    setSelectedDistrict(districtId);
    const params = {};
    if (districtId) params.district_id = districtId;
    if (selectedStage) params.stage = selectedStage;
    setSearchParams(params);
  };

  const handleStageChange = (stage) => {
    setSelectedStage(stage);
    const params = {};
    if (selectedDistrict) params.district_id = selectedDistrict;
    if (stage) params.stage = stage;
    setSearchParams(params);
  };

  const downloadReport = async (format) => {
    if (!selectedDistrict) {
      return toast.error('Please select a district first');
    }
    setLoading(true);
    try {
      const response = await api.get(
        `/admin/review/posts/${postId}/stage-report?district_id=${selectedDistrict}&stage=${selectedStage}&format=${format}`,
        { responseType: 'blob' }
      );
      const blob = new Blob(
        [response.data],
        { type: format === 'pdf' ? 'application/pdf' : 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' }
      );
      const link = document.createElement('a');
      const filename = `post_${postId}_${selectedStage.toLowerCase()}.${format === 'pdf' ? 'pdf' : 'xlsx'}`;
      link.href = window.URL.createObjectURL(blob);
      link.download = filename;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      toast.success(`Downloading ${format.toUpperCase()} report`);
    } catch (error) {
      toast.error(error.response?.data?.message || `Failed to download ${format.toUpperCase()} report`);
    } finally {
      setLoading(false);
    }
  };

  const getStageColor = (stage) => {
    const stageObj = stages.find(s => s.value === stage);
    return stageObj?.color || 'gray';
  };

  return (
    <div className="space-y-6">
      <PageHeader
        title="Final List Report"
        subtitle={post ? `${post.post_name} (${post.post_code})` : 'Loading post details...'}
      />

      {/* Filters */}
      <Card>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">
              District
            </label>
            <select
              value={selectedDistrict}
              onChange={(e) => handleDistrictChange(e.target.value)}
              className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
            >
              <option value="">Select District</option>
              <option value="ALL">All Districts</option>
              {districts.map((district) => (
                <option key={district.district_id} value={district.district_id}>
                  {district.district_name}
                </option>
              ))}
            </select>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">
              Stage
            </label>
            <div className="flex gap-2">
              {stages.map((stage) => (
                <button
                  key={stage.value}
                  onClick={() => handleStageChange(stage.value)}
                  className={`flex-1 px-4 py-2 rounded-lg font-medium transition-colors ${
                    selectedStage === stage.value
                      ? `bg-${stage.color}-600 text-white`
                      : 'bg-gray-100 text-gray-700 hover:bg-gray-200'
                  }`}
                >
                  {stage.label}
                </button>
              ))}
            </div>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">
              Download
            </label>
            <div className="flex gap-2">
              <Button
                onClick={() => downloadReport('pdf')}
                variant="secondary"
                className="flex-1"
                disabled={loading || !selectedDistrict}
              >
                <Download className="w-4 h-4 mr-2" />
                PDF
              </Button>
              <Button
                onClick={() => downloadReport('xlsx')}
                variant="secondary"
                className="flex-1"
                disabled={loading || !selectedDistrict}
              >
                <FileSpreadsheet className="w-4 h-4 mr-2" />
                Excel
              </Button>
            </div>
          </div>
        </div>
      </Card>

      {/* Summary Cards */}
      {!loading && stageHistory.length > 0 && (
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          <Card>
            <div className="flex items-center gap-4">
              <div className={`p-3 bg-${getStageColor(selectedStage)}-100 rounded-lg`}>
                <Users className={`w-6 h-6 text-${getStageColor(selectedStage)}-600`} />
              </div>
              <div>
                <div className="text-2xl font-bold text-gray-900">{stageHistory.length}</div>
                <div className="text-sm text-gray-600">Total Applications</div>
              </div>
            </div>
          </Card>

          <Card>
            <div className="flex items-center gap-4">
              <div className="p-3 bg-green-100 rounded-lg">
                <CheckCircle className="w-6 h-6 text-green-600" />
              </div>
              <div>
                <div className="text-2xl font-bold text-gray-900">
                  {stageHistory.filter(h => !h.exited_at).length}
                </div>
                <div className="text-sm text-gray-600">Currently in Stage</div>
              </div>
            </div>
          </Card>

          <Card>
            <div className="flex items-center gap-4">
              <div className="p-3 bg-blue-100 rounded-lg">
                <FileText className="w-6 h-6 text-blue-600" />
              </div>
              <div>
                <div className="text-2xl font-bold text-gray-900">
                  {stageHistory.filter(h => h.exited_at).length}
                </div>
                <div className="text-sm text-gray-600">Moved to Next Stage</div>
              </div>
            </div>
          </Card>
        </div>
      )}

      {/* Applications Table */}
      <Card>
        <div className="overflow-x-auto">
          {loading ? (
            <div className="text-center py-12">
              <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600 mx-auto"></div>
              <p className="mt-4 text-gray-600">Loading stage report...</p>
            </div>
          ) : stageHistory.length === 0 ? (
            <div className="text-center py-12">
              <FileText className="w-12 h-12 text-gray-400 mx-auto mb-4" />
              <p className="text-gray-600">No applications found in this stage</p>
              <p className="text-sm text-gray-500 mt-2">
                Select a district and stage to view the report
              </p>
            </div>
          ) : (
            <table className="min-w-full divide-y divide-gray-200">
              <thead className="bg-gray-50">
                <tr>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Application No.
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Applicant Name
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Entered Stage
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Entered By
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Exited Stage
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Current Status
                  </th>
                </tr>
              </thead>
              <tbody className="bg-white divide-y divide-gray-200">
                {reportRows.map((row) => (
                  <tr key={row.application_no} className="hover:bg-gray-50">
                    <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900">
                      {row.application_no || '—'}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                      {row.applicant_name || 'N/A'}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-600">
                      {row.gender || '—'}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-600">
                      {row.district_name || '—'}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-600">
                      {row.post_code || '—'}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-600">
                      {row.stage_status || '—'}
                    </td>
                  
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-600">
                      {row.current_status || '—'}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-600">
                      {row.selected_at || '—'}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </div>
      </Card>
    </div>
  );
};

export default StageWiseReport;
